import React from 'react';
import { Row, Col, Card, Button, Alert, Spinner } from 'react-bootstrap';

/**
 * SongSuggestions Component
 * Displays a responsive grid of song suggestion cards.
 * Props:
 * - songs: Array of song objects with fields: id, title, artist, albumImageUrl, url
 */

const SongSuggestions = ({ songs }) => {
  // Loading state
  if (songs === null) {
    return (
      <div className="text-center my-4">
        <Spinner animation="border" />
        <p>Loading songs...</p>
      </div>
    );
  }

  // Empty state
  if (!Array.isArray(songs) || songs.length === 0) {
    return (
      <Alert variant="warning" className="text-center my-4">
        No songs available for this mood.
      </Alert>
    );
  }

  return (
    <Row xs={1} sm={2} md={3} lg={4} className="g-4 mt-3">
      {songs.map((song) => (
        <Col key={song.id}>
          <Card className="h-100 shadow-lg rounded-3">
            {song.albumImageUrl && (
              <Card.Img
                variant="top"
                src={song.albumImageUrl}
                alt={`${song.title} album cover`}
                style={{ height: '180px', objectFit: 'cover' }}
              />
            )}
            <Card.Body className="d-flex flex-column">
              <Card.Title className="mb-2 text-truncate" title={song.title}>
                {song.title}
              </Card.Title>
              <Card.Text className="text-truncate text-muted mb-3" title={song.artist}>
                {song.artist}
              </Card.Text>

              <Button
                variant="success"
                href={song.url}
                target="_blank"
                rel="noopener noreferrer"
                className="mt-auto"
              >
                Listen on Spotify
              </Button>
            </Card.Body>
          </Card>
        </Col>
      ))}
    </Row>
  );
};
